class Solution {
public:
    vector<int> beautifulIndices(string s, string a, string b, int k) {
        vector<int> res;
        for (int i = 0; i <= s.size() - a.size(); i++) {
            if (s.substr(i, a.size()) == a) {
                for (int j = 0; j <= s.size() - b.size(); j++) {
                    if (s.substr(j, b.size()) == b && abs(i - j) <= k) {
                        res.push_back(i);
                        break;
                    }
                }
            }
        }
        sort(res.begin(), res.end());
        return res;
    }
};
